class Solution {
    public int binaryGap(int n) {
        String binary = Integer.toBinaryString(n);
        int maxGap = 0;
        int prevIndex = -1;
        for (int i = 0; i < binary.length(); i++) {
            if (binary.charAt(i) == '1') {
                if (prevIndex != -1) {
                    maxGap = Math.max(maxGap, i - prevIndex);
                }
                prevIndex = i;
            }
        }
        return maxGap;
    }
}
